import { loadRhapsodyGitHubEnv, type RhapsodyGitHubEnv } from "@/lib/config";

export type PullRequestCheckClassification =
	| "checks_pending"
	| "checks_success"
	| "ci_failed"
	| "checks_unknown";

export type PullRequestCheckRunSummary = {
